CREATE DATABASE tpcds_eval; USE tpcds_eval; CREATE TABLE customer (customer INT(8), c_current_addr_sk INT(8), c_current_cdemo_sk INT(8), c_customer_sk INT(8)); CREATE TABLE customer_address (customer_address INT(8), ca_address_sk INT(8)); CREATE TABLE customer_demographics (customer_demographics INT(8), cd_demo_sk INT(8)); CREATE TABLE store_sales (ss_customer_sk INT(8), store_sales INT(8), ss_sold_date_sk INT(8)); CREATE TABLE date_dim (date_dim INT(8), d_date_sk INT(8), d_year INT(8)); CREATE TABLE web_sales (web_sales INT(8), ws_bill_customer_sk INT(8), ws_sold_date_sk INT(8)); CREATE TABLE catalog_sales (catalog_sales INT(8), cs_ship_customer_sk INT(8), cs_sold_date_sk INT(8)); SELECT * FROM customer c, customer_address ca, customer_demographics, store_sales, date_dim, web_sales, catalog_sales WHERE c.c_current_addr_sk = ca.ca_address_sk AND cd_demo_sk = c.c_current_cdemo_sk AND c.c_customer_sk = ss_customer_sk AND ss_sold_date_sk = d_date_sk AND d_year = 1999 AND c.c_customer_sk = ws_bill_customer_sk AND ws_sold_date_sk = d_date_sk AND c.c_customer_sk = cs_ship_customer_sk AND cs_sold_date_sk = d_date_sk;
